SELECT count(*) FROM movie_companies, title, company_name, company_type, kind_type, movie_info, cast_info, movie_keyword, keyword WHERE movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id;